diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 96d6db2ba5bf..5b859745b7e4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5615,6 +5615,22 @@ Instruction *InstCombinerImpl::foldICmpWithMinMax(Instruction &I,
                                                   Value *Z, CmpPredicate Pred) {
   Value *X = MinMax->getLHS();
   Value *Y = MinMax->getRHS();
+  if (Pred.hasSameSign()) {
+    // The comparison is only defined when both operands have the same sign.
+    // If we can prove that the signs match, we can drop the samesign flag.
+    // Otherwise, we cannot safely simplify.
+    bool LHSKnownNonNegative = isKnownNonNegative(MinMax, SQ.getWithInstruction(&I));
+    bool LHSKnownNegative = isKnownNegative(MinMax, SQ.getWithInstruction(&I));
+    bool RHSKnownNonNegative = isKnownNonNegative(Z, SQ.getWithInstruction(&I));
+    bool RHSKnownNegative = isKnownNegative(Z, SQ.getWithInstruction(&I));
+    if ((LHSKnownNonNegative && RHSKnownNonNegative) ||
+        (LHSKnownNegative && RHSKnownNegative)) {
+      // Signs match, we can drop the samesign flag.
+      Pred = CmpPredicate(Pred, false);
+    } else {
+      return nullptr;
+    }
+  }
   if (ICmpInst::isSigned(Pred) && !MinMax->isSigned())
     return nullptr;
   if (ICmpInst::isUnsigned(Pred) && MinMax->isSigned()) {

